import { useState } from "react";
import { connectDatabase } from "../api";

const EXAMPLES = [
  { label:"Supabase",   icon:"⚡", value:"postgresql://postgres:password@db.xxx.supabase.co:5432/postgres" },
  { label:"PostgreSQL", icon:"🐘", value:"postgresql://user:password@localhost:5432/mydb" },
  { label:"MySQL",      icon:"🐬", value:"mysql+pymysql://user:password@localhost:3306/mydb" },
  { label:"SQLite",     icon:"📁", value:"sqlite:///path/to/file.db" },
];

export default function ConnectionScreen({ onConnected }) {
  const [conn, setConn]       = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState("");
  const [focused, setFocused] = useState(false);

  const connect = async () => {
    if (!conn.trim()) return;
    setLoading(true); setError("");
    try { const d = await connectDatabase(conn.trim()); onConnected(d); }
    catch (e) { setError(e.response?.data?.detail || "Connection failed. Check your connection string."); }
    finally { setLoading(false); }
  };

  return (
    <div style={S.page}>
      {/* Ambient glow blobs */}
      <div style={{ ...S.blob, top:"-15%", left:"-5%",  background:"radial-gradient(circle, rgba(99,102,241,0.12), transparent 70%)" }}/>
      <div style={{ ...S.blob, bottom:"-15%", right:"-5%", background:"radial-gradient(circle, rgba(168,85,247,0.1), transparent 70%)" }}/>

      <div style={S.card} className="fade-up">
        {/* Brand */}
        <div style={S.brand}>
          <div style={S.brandIcon}>
            <svg width="26" height="26" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="12.5" stroke="#6366f1" strokeWidth="1.5"/>
              <path d="M8 19L12 9l4 6 4-8" stroke="#6366f1" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="7" r="2.2" fill="#a855f7"/>
            </svg>
          </div>
          <div>
            <h1 style={S.brandName}>Talking BI</h1>
            <p style={S.brandSub}>AI-Powered Business Intelligence</p>
          </div>
        </div>

        <div style={S.divider}/>
        <h2 style={S.h2}>Connect your database</h2>
        <p style={S.sub}>Supports PostgreSQL, MySQL, SQLite and Supabase</p>

        {/* Input */}
        <div style={{ ...S.inputBox, ...(focused ? S.inputFocus : {}) }}>
          <svg width="15" height="15" viewBox="0 0 15 15" fill="none" style={{ flexShrink:0 }}>
            <rect x="1" y="3" width="13" height="9" rx="2" stroke="var(--text3)" strokeWidth="1.2"/>
            <path d="M4.5 7h6M4.5 9.5h4" stroke="var(--text3)" strokeWidth="1.2" strokeLinecap="round"/>
          </svg>
          <input
            style={S.inp}
            placeholder="postgresql://user:password@host:5432/dbname"
            value={conn}
            onChange={e => setConn(e.target.value)}
            onKeyDown={e => e.key==="Enter" && connect()}
            onFocus={() => setFocused(true)}
            onBlur={() => setFocused(false)}
            spellCheck={false}
          />
        </div>

        <p style={S.qLabel}>Quick fill</p>
        <div style={S.qRow}>
          {EXAMPLES.map(ex => (
            <button key={ex.label} style={S.qBtn} onClick={() => setConn(ex.value)}>
              <span>{ex.icon}</span>{ex.label}
            </button>
          ))}
        </div>

        {error && (
          <div style={S.err}>
            <svg width="13" height="13" viewBox="0 0 13 13" fill="none" style={{ flexShrink:0 }}>
              <circle cx="6.5" cy="6.5" r="6" stroke="#f43f5e" strokeWidth="1.2"/>
              <path d="M6.5 3.5v3M6.5 9v.5" stroke="#f43f5e" strokeWidth="1.2" strokeLinecap="round"/>
            </svg>
            {error}
          </div>
        )}

        <button style={{ ...S.btn, ...(loading||!conn.trim()?S.btnOff:{}) }} onClick={connect} disabled={loading||!conn.trim()}>
          {loading
            ? <><span style={S.spin}/>Connecting…</>
            : <><svg width="15" height="15" viewBox="0 0 15 15" fill="none"><path d="M2.5 7.5h10M7.5 2.5l5 5-5 5" stroke="#fff" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/></svg>Connect Database</>
          }
        </button>
        <p style={S.hint}>🔒 Your connection string stays local — never stored</p>
      </div>
    </div>
  );
}

const S = {
  page:      { minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", padding:24, position:"relative", overflow:"hidden" },
  blob:      { position:"fixed", width:"700px", height:"700px", borderRadius:"50%", pointerEvents:"none" },
  card:      { background:"var(--bg2)", border:"1px solid var(--border)", borderRadius:"var(--radius-xl)", padding:"44px 48px", width:"100%", maxWidth:520, position:"relative", zIndex:1, boxShadow:"0 0 0 1px rgba(99,102,241,0.06), 0 40px 80px rgba(0,0,0,0.5)" },
  brand:     { display:"flex", alignItems:"center", gap:14, marginBottom:28 },
  brandIcon: { width:50, height:50, background:"rgba(99,102,241,0.1)", border:"1px solid rgba(99,102,241,0.2)", borderRadius:14, display:"flex", alignItems:"center", justifyContent:"center" },
  brandName: { fontSize:24, fontWeight:800, color:"#fff", letterSpacing:"-0.5px" },
  brandSub:  { fontSize:11, color:"var(--text2)", textTransform:"uppercase", letterSpacing:"0.08em", marginTop:2 },
  divider:   { height:1, background:"var(--border)", marginBottom:28 },
  h2:        { fontSize:20, fontWeight:700, color:"#fff", marginBottom:6 },
  sub:       { fontSize:13, color:"var(--text2)", marginBottom:22 },
  inputBox:  { display:"flex", alignItems:"center", gap:10, padding:"12px 14px", background:"var(--bg3)", border:"1px solid var(--border2)", borderRadius:"var(--radius)", marginBottom:12, transition:"border-color 0.2s" },
  inputFocus:{ borderColor:"rgba(99,102,241,0.5)" },
  inp:       { flex:1, background:"none", border:"none", outline:"none", color:"var(--text)", fontSize:13, fontFamily:"'Fira Code','Cascadia Code',monospace" },
  qLabel:    { fontSize:11, color:"var(--text3)", textTransform:"uppercase", letterSpacing:"0.08em", marginBottom:8 },
  qRow:      { display:"flex", gap:8, flexWrap:"wrap", marginBottom:20 },
  qBtn:      { display:"flex", alignItems:"center", gap:6, padding:"6px 12px", background:"var(--bg3)", border:"1px solid var(--border)", borderRadius:"var(--radius)", color:"var(--text2)", fontSize:12, fontWeight:500, cursor:"pointer" },
  err:       { display:"flex", alignItems:"flex-start", gap:8, padding:"11px 14px", background:"rgba(244,63,94,0.08)", border:"1px solid rgba(244,63,94,0.2)", borderRadius:"var(--radius)", color:"#fda4af", fontSize:13, marginBottom:16, lineHeight:1.5 },
  btn:       { width:"100%", padding:14, background:"linear-gradient(135deg,#6366f1,#a855f7)", border:"none", borderRadius:"var(--radius)", color:"#fff", fontSize:15, fontWeight:700, fontFamily:"'Syne',sans-serif", cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:8, marginBottom:16, letterSpacing:"0.02em" },
  btnOff:    { opacity:0.5, cursor:"not-allowed" },
  spin:      { width:16, height:16, border:"2px solid rgba(255,255,255,0.25)", borderTopColor:"#fff", borderRadius:"50%", animation:"spin 0.7s linear infinite", display:"inline-block" },
  hint:      { textAlign:"center", fontSize:12, color:"var(--text3)" },
};
